-- 2026-06-04 - Comdata Price File screenshot for Business Review Slide 5
--
-- Fills the 's5-shot' image slot on Slide 5 ("Operational Savings -
-- Comdata Price File Impact"), the right-hand panel that supports the
-- 'Recover the discount admin fee - every month.' headline. Auto-renders
-- on every truck stop's Business Review via gallerySrc({slot:'s5-shot'})
-- - no per-stop work.
--
-- File is ASCII-only on purpose (see prior vendor-logo bug from 2026-06-04).
-- Idempotent: ON CONFLICT (id) DO UPDATE - re-running with a newer
-- screenshot replaces in place.

BEGIN;

INSERT INTO public.deck_gallery (id, slot_key, label, category, vendor_id, data_url, notes, updated_at) VALUES
  ('g_slot_s5_shot', 's5-shot', 'Comdata Price File settlement screenshot', 'hero', NULL, 'data:image/jpeg;base64,', 'Uploaded 2026-06-04 via add_price_file_screenshot.py - 100178 bytes source', now())
ON CONFLICT (id) DO UPDATE SET
  data_url   = EXCLUDED.data_url,
  label      = EXCLUDED.label,
  category   = EXCLUDED.category,
  slot_key   = EXCLUDED.slot_key,
  notes      = EXCLUDED.notes,
  updated_at = EXCLUDED.updated_at;

COMMIT;

